## Code Example
```javascript
// Pseudo Dataflow skeleton (not runnable)
class TenantPipeline {
  constructor(tenantId, projectId) {
    this.tenantId = tenantId;
    this.projectId = projectId;
    this.datasetId = `tenant_${tenantId}`;
  }

  buildPipeline(pubsubSubscription, watermarkDelayMs = 60000) {
    return (
      pipeline
        .apply('ReadFromPubSub', PubsubIO.readMessages()
          .fromSubscription(this.pubsubSubscription)
          .withTimestampAttribute('event_timestamp'))
        .apply('ExtractTenant', ParDo.of(new ExtractTenantDoFn()))
        .apply('WindowInto', Window.into(FixedWindows.of(60 * 60 * 1000))
          .withAllowedLateness(watermarkDelayMs)
          .triggering(AfterWatermark.pastEndOfWindow()
            .withEarlyFirings(AfterProcessingTime.pastFirstElementInPane()
              .plusDelayOf(5 * 60 * 1000))))
        .apply('ApplyTenantLabels', ParDo.of(new AddBillingLabelsDoFn(this.tenantId)))
        .apply('WriteToBigQuery', BigQueryIO.write()
          .to(tableSpec => this.getTableSpec(tableSpec))
          .withSchema(this.getSchema())
          .withWriteDisposition(BigQuery.WriteDisposition.WRITE_APPEND)
          .withCreateDisposition(BigQuery.CreateDisposition.CREATE_NEVER));
    }
  }

  getTableSpec(tableSpec) {
    return `${this.projectId}:${this.datasetId}.${tableSpec}`;
  }
}
```

