## Code Example
```javascript
// validateSignedUrl.js
const {Storage} = require('@google-cloud/storage');
const {PubSub} = require('@google-cloud/pubsub');

const storage = new Storage();
const pubsub = new PubSub();

exports.validateSignedUrl = async (req, res) => {
  const {url} = req.body;

  try {
    // Parse bucket and object from URL
    const urlObj = new URL(url);
    const pathParts = urlObj.pathname.substring(1).split('/');
    const bucketName = pathParts[0];
    const fileName = pathParts.slice(1).join('/');

    // Verify signed URL using Cloud Storage SDK
    const [exists] = await storage.bucket(bucketName).file(fileName).exists();
    if (!exists) {
      res.status(404).json({error: 'File not found'});
      return;
    }

    // Publish to Dataflow trigger topic
    const topic = pubsub.topic(`dataflow-trigger-${process.env.ENV}`);
    await topic.publishJSON({
      url,
      bucket: bucketName,
      fileName,
      timestamp: new Date().toISOString()
    });

    res.status(200).json({message: 'Validation successful'});
  } catch (error) {
    console.error('Validation error:', error);
    res.status(500).json({error: 'Validation failed'});
  }
};
```

