app.get('/flag', async (req, res) => {
  const tenant = req.query.tenant_id;
  const key = req.query.flag_key;
  const cacheKey = `flag:${tenant}:${key}`;
  const cached = await redis.get(cacheKey);
  if (cached) return res.json({flag_value: JSON.parse(cached)});
  const doc = await firestore.collection('tenants').doc(tenant).collection('flags').doc(key).get();
  const value = doc.exists ? doc.data().value : process.env.DEFAULT_FLAG
  await redis.set(cacheKey, JSON.stringify(value), 'EX', 300);
  res.json({flag_value: value});
});
```

